window.AIDA_DATA.cantoneseGrammar = {"metadata":{"language":"Cantonese","type":"grammar","count":102,"sources":["https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia.htm","https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf"],"cross_verified_count":62},"items":[{"id":"yue-g-001","pattern":"A 係 B","jyutping":"A hai6 B","meaning":"A is B; equates two noun phrases.","category":"copula","level":"Beginner","usage_note":"Use 係 to identify or equate nouns. Do not insert it before ordinary adjectives the way English uses 'be'.","register":"neutral","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"3.1 Equating two nouns with 係"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/08.htm","section":"Chapter 8"}],"cross_verified":true},{"id":"yue-g-002","pattern":"A 喺 PLACE","jyutping":"A hai2 PLACE","meaning":"A is at/in a location.","category":"location","level":"Beginner","usage_note":"喺 is the everyday spoken location verb/preposition. It is different from 係 'to be/equal'.","register":"conversational","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"3.2 Indicating location with 喺"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/07.htm","section":"Chapter 7"}],"cross_verified":true},{"id":"yue-g-003","pattern":"SUBJECT + 好 + ADJ","jyutping":"SUBJECT + hou2 + ADJ","meaning":"Predicative adjective: SUBJECT is ADJ.","category":"adjective","level":"Beginner","usage_note":"Cantonese adjectives can act like stative verbs. 好 often appears before a bare adjective in neutral descriptions.","register":"neutral","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"3.3.1 Predicative adjectives"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/09.htm","section":"Chapter 9"}],"cross_verified":true},{"id":"yue-g-004","pattern":"ADJ + 嘅 + NOUN","jyutping":"ADJ + ge3 + NOUN","meaning":"Attributive adjective modifying a noun.","category":"noun-modification","level":"Beginner","usage_note":"嘅 links a description to a noun; in short fixed adjective-noun combinations it may be omitted.","register":"neutral","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"3.3.2 Attributive adjectives with 嘅"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/09.htm","section":"Chapter 9"}],"cross_verified":true},{"id":"yue-g-005","pattern":"SUBJECT + 有 + NOUN","jyutping":"SUBJECT + jau5 + NOUN","meaning":"Have/possess; there is/are depending on context.","category":"existential","level":"Beginner","usage_note":"有 covers possession and existence. Context determines whether English uses 'have' or 'there is'.","register":"neutral","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"3.4 Expressing possession and existence with 有"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/14.htm","section":"Chapter 14"}],"cross_verified":true},{"id":"yue-g-006","pattern":"NUMBER + CLASSIFIER + NOUN","jyutping":"NUMBER + CL + NOUN","meaning":"Count nouns using a classifier.","category":"classifier","level":"Beginner","usage_note":"Classifiers are obligatory in many counting and demonstrative contexts. 個 is common but not a universal substitute.","register":"neutral","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"4.1.1 Classifiers"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/06.htm","section":"Chapter 6"}],"cross_verified":true},{"id":"yue-g-007","pattern":"呢 + CLASSIFIER + NOUN","jyutping":"ni1 + CL + NOUN","meaning":"this + noun.","category":"demonstrative","level":"Beginner","usage_note":"Spoken Cantonese normally uses a classifier between 呢 and a count noun.","register":"conversational","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"4.1.2 Demonstratives"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/06.htm","section":"Chapter 6"}],"cross_verified":true},{"id":"yue-g-008","pattern":"嗰 + CLASSIFIER + NOUN","jyutping":"go2 + CL + NOUN","meaning":"that + noun.","category":"demonstrative","level":"Beginner","usage_note":"Use 嗰 with a classifier for 'that/those' in ordinary speech.","register":"conversational","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"4.1.2 Demonstratives"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/06.htm","section":"Chapter 6"}],"cross_verified":true},{"id":"yue-g-009","pattern":"PRONOUN + 嘅 + NOUN","jyutping":"PRONOUN + ge3 + NOUN","meaning":"Possessive noun phrase.","category":"possession","level":"Beginner","usage_note":"嘅 marks possession; with close relationships and some common nouns, colloquial Cantonese may omit it.","register":"neutral","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"4.1.3 Possessives"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/06.htm","section":"Chapter 6"}],"cross_verified":true},{"id":"yue-g-010","pattern":"PRONOUN + 哋","jyutping":"PRONOUN + dei6","meaning":"Plural human pronoun.","category":"pronoun","level":"Beginner","usage_note":"哋 pluralizes personal pronouns and some human nouns, not ordinary inanimate nouns.","register":"conversational","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"4.3 Pronouns"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/05.htm","section":"Chapter 5"}],"cross_verified":true},{"id":"yue-g-011","pattern":"S + V + O","jyutping":"S + V + O","meaning":"Basic subject-verb-object order.","category":"word-order","level":"Beginner","usage_note":"The basic order is SVO, but spoken Cantonese is strongly topic-prominent and often rearranges already-known information.","register":"neutral","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.1 Transitive and intransitive verbs"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/04.htm","section":"Chapter 4"}],"cross_verified":true},{"id":"yue-g-012","pattern":"V + DIRECT OBJECT + 畀 + INDIRECT OBJECT","jyutping":"V + DO + bei2 + IO","meaning":"Double-object / recipient construction.","category":"valency","level":"Intermediate","usage_note":"畀 introduces the recipient after the thing transferred. With 畀 as the main verb, a second 畀 may appear before the recipient.","register":"neutral","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.1 Transitive and intransitive verbs"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/08.htm","section":"Chapter 8"}],"cross_verified":true},{"id":"yue-g-013","pattern":"VERB + OBJECT compound","jyutping":"V + O","meaning":"Verb-object compound such as 食飯 or 行街.","category":"word-formation","level":"Beginner","usage_note":"Many everyday Cantonese verbs are verb-object compounds and may allow aspect markers to appear inside the compound.","register":"conversational","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.1 Transitive and intransitive verbs"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/08.htm","section":"Chapter 8"}],"cross_verified":true},{"id":"yue-g-014","pattern":"唔 + VERB/ADJ","jyutping":"m4 + V/ADJ","meaning":"General non-past, habitual, or property negation.","category":"negation","level":"Beginner","usage_note":"Use for 'not/do not' in ordinary present, habitual, or adjectival contexts.","register":"neutral","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.2 Negating a verb"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/13.htm","section":"Chapter 13"}],"cross_verified":true},{"id":"yue-g-015","pattern":"冇 + VERB","jyutping":"mou5 + V","meaning":"Negative perfective: did not / have not.","category":"negation","level":"Beginner","usage_note":"Common for an event that did not occur; also the negative of 有.","register":"neutral","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.2 Negating a verb"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/13.htm","section":"Chapter 13"}],"cross_verified":true},{"id":"yue-g-016","pattern":"未 + VERB","jyutping":"mei6 + V","meaning":"Not yet.","category":"negation","level":"Beginner","usage_note":"Implies the event has not happened up to now and remains open or expected.","register":"neutral","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.2 Negating a verb"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/13.htm","section":"Chapter 13"}],"cross_verified":true},{"id":"yue-g-017","pattern":"唔係 + CLAUSE","jyutping":"m4 hai6 + CLAUSE","meaning":"It is not the case that...; contrastive negation.","category":"negation","level":"Beginner","usage_note":"Often corrects an assumption or contrasts the actual situation with another.","register":"neutral","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.2 Negating a verb"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/13.htm","section":"Chapter 13"}],"cross_verified":true},{"id":"yue-g-018","pattern":"TIME + SUBJECT + VERB / SUBJECT + TIME + VERB","jyutping":"","meaning":"Flexible time-adverb placement before the verb.","category":"time","level":"Beginner","usage_note":"Time expressions can come before or after the subject, but normally precede the verb phrase.","register":"neutral","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.3 Time adverbs and aspect markers"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/11.htm","section":"Chapter 11"}],"cross_verified":true},{"id":"yue-g-019","pattern":"VERB + 緊","jyutping":"V + gan2","meaning":"Progressive; action currently in progress.","category":"aspect","level":"Beginner","usage_note":"Highlights an ongoing dynamic activity. Aspect choice reflects how the speaker views the event, not grammatical tense.","register":"conversational","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.3 Time adverbs and aspect markers"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/11.htm","section":"Chapter 11"}],"cross_verified":true},{"id":"yue-g-020","pattern":"喺度 + VERB + 緊","jyutping":"hai2 dou6 + V + gan2","meaning":"Explicit progressive frame.","category":"aspect","level":"Intermediate","usage_note":"Adds an 'in the middle of doing' flavor and is common in speech. Aspect choice reflects how the speaker views the event, not grammatical tense.","register":"conversational","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.3 Time adverbs and aspect markers"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/11.htm","section":"Chapter 11"}],"cross_verified":true},{"id":"yue-g-021","pattern":"VERB + 住","jyutping":"V + zyu6","meaning":"Continuous state or sustained activity.","category":"aspect","level":"Intermediate","usage_note":"Often describes a state that is being maintained rather than a changing action. Aspect choice reflects how the speaker views the event, not grammatical tense.","register":"conversational","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.3 Time adverbs and aspect markers"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/11.htm","section":"Chapter 11"}],"cross_verified":true},{"id":"yue-g-022","pattern":"VERB + 開","jyutping":"V + hoi1","meaning":"Habitual aspect; usually does.","category":"aspect","level":"Intermediate","usage_note":"Marks an established habit or usual activity. Aspect choice reflects how the speaker views the event, not grammatical tense.","register":"conversational","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.3 Time adverbs and aspect markers"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/11.htm","section":"Chapter 11"}],"cross_verified":true},{"id":"yue-g-023","pattern":"VERB + 過","jyutping":"V + gwo3","meaning":"Experiential aspect; have ever done.","category":"aspect","level":"Beginner","usage_note":"Frames an event as past experience, not merely a completed recent event. Aspect choice reflects how the speaker views the event, not grammatical tense.","register":"conversational","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.3 Time adverbs and aspect markers"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/11.htm","section":"Chapter 11"}],"cross_verified":true},{"id":"yue-g-024","pattern":"VERB + 咗","jyutping":"V + zo2","meaning":"Perfective / completed event with current relevance.","category":"aspect","level":"Beginner","usage_note":"One of the most frequent aspect markers in speech; it is not a simple past-tense suffix. Aspect choice reflects how the speaker views the event, not grammatical tense.","register":"conversational","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.3 Time adverbs and aspect markers"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/11.htm","section":"Chapter 11"}],"cross_verified":true},{"id":"yue-g-025","pattern":"VERB + 完","jyutping":"V + jyun4","meaning":"Finish doing; completion to the endpoint.","category":"aspect","level":"Intermediate","usage_note":"Emphasizes that the activity has been completed. Aspect choice reflects how the speaker views the event, not grammatical tense.","register":"conversational","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.3 Time adverbs and aspect markers"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/11.htm","section":"Chapter 11"}],"cross_verified":true},{"id":"yue-g-026","pattern":"VERB + 晒","jyutping":"V + saai3","meaning":"All/completely; exhaustive completion.","category":"aspect","level":"Intermediate","usage_note":"Often emphasizes totality and may carry an evaluative tone. Aspect choice reflects how the speaker views the event, not grammatical tense.","register":"conversational","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.3 Time adverbs and aspect markers"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/11.htm","section":"Chapter 11"}],"cross_verified":true},{"id":"yue-g-027","pattern":"VERB + 吓","jyutping":"V + haa5","meaning":"Do briefly / try doing.","category":"aspect","level":"Beginner","usage_note":"Common softener for small actions, suggestions, and requests. Aspect choice reflects how the speaker views the event, not grammatical tense.","register":"conversational","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.3 Time adverbs and aspect markers"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/11.htm","section":"Chapter 11"}],"cross_verified":true},{"id":"yue-g-028","pattern":"VERB + 埋","jyutping":"V + maai4","meaning":"Do/add as well; include; finish the remainder.","category":"aspect","level":"Intermediate","usage_note":"Adds an inclusion/addition nuance and can sometimes imply disapproval. Aspect choice reflects how the speaker views the event, not grammatical tense.","register":"conversational","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.3 Time adverbs and aspect markers"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/11.htm","section":"Chapter 11"}],"cross_verified":true},{"id":"yue-g-029","pattern":"VERB + 到","jyutping":"V + dou2","meaning":"Resultative success / manage to / reach a result.","category":"aspect","level":"Intermediate","usage_note":"Distinguish resultative 到 dou2 from extent 到 dou3. Aspect choice reflects how the speaker views the event, not grammatical tense.","register":"conversational","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.3 Time adverbs and aspect markers"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/11.htm","section":"Chapter 11"}],"cross_verified":true},{"id":"yue-g-030","pattern":"VERB + 落去","jyutping":"V + lok6 heoi3","meaning":"Continue doing.","category":"aspect","level":"Intermediate","usage_note":"Marks continuation forward from the current point. Aspect choice reflects how the speaker views the event, not grammatical tense.","register":"conversational","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.3 Time adverbs and aspect markers"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/11.htm","section":"Chapter 11"}],"cross_verified":true},{"id":"yue-g-031","pattern":"VERB + 極 + 都...","jyutping":"V + gik6 + dou1...","meaning":"No matter how much one does V...","category":"aspect","level":"Intermediate","usage_note":"Emphasizes an action taken to an extreme with a contrasting result. Aspect choice reflects how the speaker views the event, not grammatical tense.","register":"conversational","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.3 Time adverbs and aspect markers"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/11.htm","section":"Chapter 11"}],"cross_verified":true},{"id":"yue-g-032","pattern":"VERB + 親 + 都...","jyutping":"V + can1 + dou1...","meaning":"Every time V happens...","category":"aspect","level":"Intermediate","usage_note":"A compact conversational way to express repeated triggering events. Aspect choice reflects how the speaker views the event, not grammatical tense.","register":"conversational","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.3 Time adverbs and aspect markers"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/11.htm","section":"Chapter 11"}],"cross_verified":true},{"id":"yue-g-033","pattern":"VERB + 起上嚟","jyutping":"V + hei2 soeng5 lei4","meaning":"Begin/start doing; inchoative.","category":"aspect","level":"Intermediate","usage_note":"Marks the onset of an event, emotion, or state. Aspect choice reflects how the speaker views the event, not grammatical tense.","register":"conversational","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.3 Time adverbs and aspect markers"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/11.htm","section":"Chapter 11"}],"cross_verified":true},{"id":"yue-g-034","pattern":"Multiple aspect markers in one verb phrase","jyutping":"","meaning":"Aspect markers may stack when their meanings are compatible.","category":"aspect","level":"Advanced","usage_note":"Stacked markers such as 埋 + 落去 or 住 + 晒 combine viewpoint meanings; order matters.","register":"conversational","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.3 Time adverbs and aspect markers"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/11.htm","section":"Chapter 11"}],"cross_verified":true},{"id":"yue-g-035","pattern":"喺 + LOCATION/TIME","jyutping":"hai2 + location/time","meaning":"At/in a place or, more emphatically, at a time.","category":"preposition","level":"Intermediate","usage_note":"Introduces event location; negating the location phrase is different from negating the main verb.","register":"neutral","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.4 Prepositional phrases"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/07.htm","section":"Chapter 7"}],"cross_verified":true},{"id":"yue-g-036","pattern":"同 + PERSON + VERB","jyutping":"tung4 + person + V","meaning":"Do something with someone.","category":"preposition","level":"Intermediate","usage_note":"Common comitative use of 同.","register":"neutral","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.4 Prepositional phrases"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/07.htm","section":"Chapter 7"}],"cross_verified":true},{"id":"yue-g-037","pattern":"同 + PERSON + VERB","jyutping":"tung4 + person + V","meaning":"Direct an action toward someone.","category":"preposition","level":"Intermediate","usage_note":"Context can make 同 mean 'to' rather than 'with'.","register":"neutral","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.4 Prepositional phrases"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/07.htm","section":"Chapter 7"}],"cross_verified":true},{"id":"yue-g-038","pattern":"同 + PERSON + VERB","jyutping":"tung4 + person + V","meaning":"Do something for someone's sake / directive stance.","category":"preposition","level":"Intermediate","usage_note":"In commands this can sound forceful, roughly 'for me, do X'.","register":"neutral","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.4 Prepositional phrases"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/07.htm","section":"Chapter 7"}],"cross_verified":true},{"id":"yue-g-039","pattern":"對 / 向 + PERSON/PLACE + VERB","jyutping":"deoi3 / hoeng3 + X + V","meaning":"Toward/to X.","category":"preposition","level":"Intermediate","usage_note":"Directional or target-marking prepositional phrase.","register":"neutral","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.4 Prepositional phrases"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/07.htm","section":"Chapter 7"}],"cross_verified":true},{"id":"yue-g-040","pattern":"由 + SOURCE + VERB","jyutping":"jau4 + source + V","meaning":"From a source or starting point.","category":"preposition","level":"Intermediate","usage_note":"Marks origin or point of departure.","register":"neutral","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.4 Prepositional phrases"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/07.htm","section":"Chapter 7"}],"cross_verified":true},{"id":"yue-g-041","pattern":"都 + VP/ADJ","jyutping":"dou1 + VP/ADJ","meaning":"also; all/every, depending on scope.","category":"adverb","level":"Intermediate","usage_note":"Scope is important: 都 can link similar predicates or quantify over the entire subject.","register":"conversational","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.5 Logical adverbs"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/10.htm","section":"Chapter 10"}],"cross_verified":true},{"id":"yue-g-042","pattern":"又 + VP","jyutping":"jau6 + VP","meaning":"also/again; add another predicate for the same subject.","category":"adverb","level":"Intermediate","usage_note":"Often links an additional action or property.","register":"conversational","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.5 Logical adverbs"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/10.htm","section":"Chapter 10"}],"cross_verified":true},{"id":"yue-g-043","pattern":"淨係 + VP","jyutping":"zing6 hai6 + VP","meaning":"only / merely.","category":"adverb","level":"Intermediate","usage_note":"Common conversational limiter.","register":"conversational","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.5 Logical adverbs"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/10.htm","section":"Chapter 10"}],"cross_verified":true},{"id":"yue-g-044","pattern":"仲 + VP","jyutping":"zung6 + VP","meaning":"still; furthermore; in addition.","category":"adverb","level":"Intermediate","usage_note":"Can mark continuation in time or add another point.","register":"conversational","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.5 Logical adverbs"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/10.htm","section":"Chapter 10"}],"cross_verified":true},{"id":"yue-g-045","pattern":"...就...","jyutping":"...zau6...","meaning":"then/subsequently; precisely/emphatically.","category":"adverb","level":"Intermediate","usage_note":"Meaning depends heavily on clause structure and discourse context.","register":"conversational","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.5 Logical adverbs"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/10.htm","section":"Chapter 10"}],"cross_verified":true},{"id":"yue-g-046","pattern":"先 + VP","jyutping":"sin1 + VP","meaning":"only then; first; later-than-expected/less-than-expected.","category":"adverb","level":"Intermediate","usage_note":"A high-frequency particle/adverb whose interpretation depends on sequence and expectation.","register":"conversational","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.5 Logical adverbs"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/10.htm","section":"Chapter 10"}],"cross_verified":true},{"id":"yue-g-047","pattern":"ADJ + 咁 + VERB","jyutping":"ADJ + gam2 + V","meaning":"Do V in an ADJ manner.","category":"adverbial","level":"Intermediate","usage_note":"Productive way to turn an adjective-like description into a manner adverb.","register":"conversational","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.6-6.7 Adverbs of manner / extent"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/10.htm","section":"Chapter 10"}],"cross_verified":true},{"id":"yue-g-048","pattern":"VERB + 得 + ADJ/PHRASE","jyutping":"V + dak1 + description","meaning":"Describe how well/in what manner an action is done.","category":"adverbial","level":"Intermediate","usage_note":"The description follows the verb through 得.","register":"conversational","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.6-6.7 Adverbs of manner / extent"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/10.htm","section":"Chapter 10"}],"cross_verified":true},{"id":"yue-g-049","pattern":"REDUPLICATED ADVERB + (咁) + VERB","jyutping":"","meaning":"Reduplicated adverbial manner expression.","category":"adverbial","level":"Intermediate","usage_note":"咁 may be optional when the preceding form is already adverbial.","register":"conversational","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.6-6.7 Adverbs of manner / extent"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/10.htm","section":"Chapter 10"}],"cross_verified":true},{"id":"yue-g-050","pattern":"係咁 + VERB","jyutping":"hai6 gam2 + V","meaning":"Keep doing / do non-stop.","category":"adverbial","level":"Intermediate","usage_note":"Very conversational; emphasizes repeated or continuous action.","register":"conversational","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.6-6.7 Adverbs of manner / extent"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/10.htm","section":"Chapter 10"}],"cross_verified":true},{"id":"yue-g-051","pattern":"VERB + 到 + RESULT","jyutping":"V + dou3 + result","meaning":"So...that; action reaches an extreme result.","category":"adverbial","level":"Intermediate","usage_note":"Often used in vivid or exaggerated descriptions. This is extent 到 dou3, not resultative 到 dou2.","register":"conversational","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.6-6.7 Adverbs of manner / extent"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/10.htm","section":"Chapter 10"}],"cross_verified":true},{"id":"yue-g-052","pattern":"VERB + NUMBER + 次","jyutping":"V + number + ci3","meaning":"Count occurrences of an action.","category":"verb-complement","level":"Intermediate","usage_note":"Neutral general-purpose action counter.","register":"conversational","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.8-6.9 Verbal classifiers / serial verbs"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/08.htm","section":"Chapter 8"}],"cross_verified":true},{"id":"yue-g-053","pattern":"VERB + 一下","jyutping":"V + jat1 haa5","meaning":"One brief occurrence / a little.","category":"verb-complement","level":"Intermediate","usage_note":"Often softens an action or request.","register":"conversational","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.8-6.9 Verbal classifiers / serial verbs"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/08.htm","section":"Chapter 8"}],"cross_verified":true},{"id":"yue-g-054","pattern":"VERB + 一餐","jyutping":"V + jat1 caan1","meaning":"An extended bout/session of an activity.","category":"verb-complement","level":"Intermediate","usage_note":"Originally a meal classifier; colloquially extends to event duration.","register":"conversational","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.8-6.9 Verbal classifiers / serial verbs"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/08.htm","section":"Chapter 8"}],"cross_verified":true},{"id":"yue-g-055","pattern":"VERB + NUMBER + 聲","jyutping":"V + number + seng1","meaning":"Count utterances, cries, or sounds.","category":"verb-complement","level":"Intermediate","usage_note":"Uses 'sound' as a verbal classifier.","register":"conversational","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.8-6.9 Verbal classifiers / serial verbs"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/08.htm","section":"Chapter 8"}],"cross_verified":true},{"id":"yue-g-056","pattern":"VERB + 一眼 / 一腳 / 一拳","jyutping":"","meaning":"Body-part noun used as an action classifier.","category":"verb-complement","level":"Intermediate","usage_note":"Common with looking, kicking, punching, and similar actions.","register":"conversational","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.8-6.9 Verbal classifiers / serial verbs"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/08.htm","section":"Chapter 8"}],"cross_verified":true},{"id":"yue-g-057","pattern":"VERB1 + VERB2","jyutping":"V1 + V2","meaning":"Serial verb construction.","category":"verb-complement","level":"Intermediate","usage_note":"Cantonese can string verbs together without an overt conjunction when they form one complex event.","register":"conversational","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.8-6.9 Verbal classifiers / serial verbs"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/08.htm","section":"Chapter 8"}],"cross_verified":true},{"id":"yue-g-058","pattern":"VERB + 畀 + PERSON + VERB","jyutping":"V + bei2 + person + V","meaning":"Cause/allow/perform for someone to experience the second verb.","category":"verb-complement","level":"Intermediate","usage_note":"Common serial pattern in speech; 畀 can mark recipient or passive-like relations depending on structure.","register":"conversational","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"6.8-6.9 Verbal classifiers / serial verbs"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/08.htm","section":"Chapter 8"}],"cross_verified":true},{"id":"yue-g-059","pattern":"OBJECT + SUBJECT + VERB","jyutping":"","meaning":"Object/topic fronting; topic-comment order.","category":"topicalization","level":"Intermediate","usage_note":"Fronted objects are common when the topic is already salient; this is not simply random word-order variation.","register":"varies","aliases":[],"sources":[{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/04.htm","section":"Chapter 4"}],"cross_verified":false},{"id":"yue-g-060","pattern":"VERB + SUBJECT","jyutping":"","meaning":"Verb-subject order in restricted constructions.","category":"word-order","level":"Advanced","usage_note":"Occurs in particular event-presentational and idiomatic structures rather than as the default order.","register":"varies","aliases":[],"sources":[{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/04.htm","section":"Chapter 4"}],"cross_verified":false},{"id":"yue-g-061","pattern":"CLAUSE ..., SUBJECT/AUX","jyutping":"","meaning":"Right-dislocation.","category":"discourse","level":"Advanced","usage_note":"A trailing subject or auxiliary can be added after the main clause in colloquial speech for afterthought or stance.","register":"varies","aliases":[],"sources":[{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/04.htm","section":"Chapter 4"}],"cross_verified":false},{"id":"yue-g-062","pattern":"TOPIC + COMMENT","jyutping":"","meaning":"Hanging topic / double-subject construction.","category":"topicalization","level":"Advanced","usage_note":"Cantonese is topic-prominent: a broad topic can stand outside the core clause.","register":"varies","aliases":[],"sources":[{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/04.htm","section":"Chapter 4"}],"cross_verified":false},{"id":"yue-g-063","pattern":"SUBJECT + SECONDARY TOPIC + PREDICATE","jyutping":"","meaning":"Secondary topicalization.","category":"topicalization","level":"Advanced","usage_note":"A second topic-like phrase can appear inside the comment, especially in colloquial discourse.","register":"varies","aliases":[],"sources":[{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/04.htm","section":"Chapter 4"}],"cross_verified":false},{"id":"yue-g-064","pattern":"STATIVE VERB without 係","jyutping":"","meaning":"Stative verbs function predicatively.","category":"verb-type","level":"Beginner","usage_note":"Many meanings translated with English 'be + adjective/state' use a stative verb directly.","register":"varies","aliases":[],"sources":[{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/08.htm","section":"Chapter 8"}],"cross_verified":false},{"id":"yue-g-065","pattern":"PERCEPTION VERB + complement","jyutping":"","meaning":"Perception verb constructions.","category":"verb-type","level":"Intermediate","usage_note":"Perception verbs interact with result complements and potential forms in ways that differ from English.","register":"varies","aliases":[],"sources":[{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/08.htm","section":"Chapter 8"}],"cross_verified":false},{"id":"yue-g-066","pattern":"COGNITION VERB + CLAUSE","jyutping":"","meaning":"Cognition verbs taking clausal complements.","category":"verb-type","level":"Intermediate","usage_note":"Verbs such as 覺得 introduce opinions or judgments; the following clause commonly omits an explicit complementizer.","register":"varies","aliases":[],"sources":[{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/08.htm","section":"Chapter 8"}],"cross_verified":false},{"id":"yue-g-067","pattern":"QUANTIFIED OBJECT around the verb phrase","jyutping":"","meaning":"Quantified object constructions.","category":"quantification","level":"Advanced","usage_note":"Whole-quantity expressions can interact with the verb and particles, and placement affects scope.","register":"varies","aliases":[],"sources":[{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/08.htm","section":"Chapter 8"}],"cross_verified":false},{"id":"yue-g-068","pattern":"AA / AABB adjective reduplication","jyutping":"","meaning":"Intensifying or stylistic adjective reduplication.","category":"reduplication","level":"Intermediate","usage_note":"Reduplication is productive and often carries expressive, distributive, or degree-related meaning.","register":"varies","aliases":[],"sources":[{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/09.htm","section":"Chapter 9"}],"cross_verified":false},{"id":"yue-g-069","pattern":"ADJ-ADJ-哋","jyutping":"","meaning":"Slightly/rather ADJ.","category":"reduplication","level":"Intermediate","usage_note":"A colloquial attenuative pattern meaning roughly 'a bit/rather ADJ'.","register":"varies","aliases":[],"sources":[{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/09.htm","section":"Chapter 9"}],"cross_verified":false},{"id":"yue-g-070","pattern":"ABB expressive adjective","jyutping":"","meaning":"Expressive adjective pattern such as 熱辣辣.","category":"reduplication","level":"Advanced","usage_note":"Highly idiomatic and vivid; best learned as lexicalized sound-symbolic patterns.","register":"varies","aliases":[],"sources":[{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/09.htm","section":"Chapter 9"}],"cross_verified":false},{"id":"yue-g-071","pattern":"ADJ + 咗","jyutping":"ADJ + zo2","meaning":"Become more ADJ than before.","category":"comparison","level":"Intermediate","usage_note":"Perfective 咗 can mark a change of state, yielding a comparative 'more ... than before' reading.","register":"varies","aliases":[],"sources":[{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/09.htm","section":"Chapter 9"}],"cross_verified":false},{"id":"yue-g-072","pattern":"越 A 越 B","jyutping":"jyut6 A jyut6 B","meaning":"The more A, the more B.","category":"comparison","level":"Intermediate","usage_note":"Productive correlative comparative construction.","register":"varies","aliases":[],"sources":[{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/09.htm","section":"Chapter 9"}],"cross_verified":false},{"id":"yue-g-073","pattern":"A-not-A","jyutping":"","meaning":"Yes/no question by repeating a predicate with negation.","category":"question","level":"Beginner","usage_note":"Very common in spoken Cantonese and often more natural than relying only on a final question particle.","register":"varies","aliases":[],"sources":[{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/17.htm","section":"Chapter 17"}],"cross_verified":false},{"id":"yue-g-074","pattern":"係唔係 + CLAUSE","jyutping":"hai6 m4 hai6 + clause","meaning":"Is it the case that...? / yes-no question.","category":"question","level":"Beginner","usage_note":"Useful for proposition-level yes/no questions and checking assumptions.","register":"varies","aliases":[],"sources":[{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/17.htm","section":"Chapter 17"}],"cross_verified":false},{"id":"yue-g-075","pattern":"VERB + 未?","jyutping":"V + mei6","meaning":"Have you V-ed yet?","category":"question","level":"Beginner","usage_note":"Common perfective/yet-question pattern; often occurs with sentence-final 呀.","register":"varies","aliases":[],"sources":[{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/17.htm","section":"Chapter 17"}],"cross_verified":false},{"id":"yue-g-076","pattern":"有冇 + NOUN/VERB","jyutping":"jau5 mou5 + X","meaning":"Is there / do you have / did you...?","category":"question","level":"Beginner","usage_note":"A high-frequency have-not-have question frame.","register":"varies","aliases":[],"sources":[{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/17.htm","section":"Chapter 17"}],"cross_verified":false},{"id":"yue-g-077","pattern":"CLAUSE + 得唔得?","jyutping":"clause + dak1 m4 dak1","meaning":"Is it okay? / can it work?","category":"question","level":"Beginner","usage_note":"Often used as a tag to ask for approval or agreement.","register":"varies","aliases":[],"sources":[{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/17.htm","section":"Chapter 17"}],"cross_verified":false},{"id":"yue-g-078","pattern":"Statement + rising intonation","jyutping":"","meaning":"Echo or incredulous question.","category":"question","level":"Intermediate","usage_note":"Cantonese can form a question through intonation and discourse context without changing word order.","register":"varies","aliases":[],"sources":[{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/17.htm","section":"Chapter 17"}],"cross_verified":false},{"id":"yue-g-079","pattern":"TOPIC + sentence particle","jyutping":"","meaning":"Topic particles.","category":"sentence-particle","level":"Advanced","usage_note":"Topic particles manage attention and stance; tone and context are essential.","register":"varies","aliases":[],"sources":[{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/18.htm","section":"Chapter 18"}],"cross_verified":false},{"id":"yue-g-080","pattern":"CLAUSE + sentence-final particle","jyutping":"","meaning":"Clause-final particle system.","category":"sentence-particle","level":"Intermediate","usage_note":"Final particles encode attitude, evidence, politeness, shared knowledge, and emotional stance.","register":"varies","aliases":[],"sources":[{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/18.htm","section":"Chapter 18"}],"cross_verified":false},{"id":"yue-g-081","pattern":"PARTICLE + PARTICLE","jyutping":"","meaning":"Sentence-final particle combinations.","category":"sentence-particle","level":"Advanced","usage_note":"Particles can stack in constrained orders, combining discourse meanings rather than simply adding translations.","register":"varies","aliases":[],"sources":[{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/18.htm","section":"Chapter 18"}],"cross_verified":false},{"id":"yue-g-082","pattern":"QUESTION + final particle","jyutping":"","meaning":"Question particles.","category":"sentence-particle","level":"Intermediate","usage_note":"Final particles tune the force, expectation, and social feel of a question.","register":"varies","aliases":[],"sources":[{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/18.htm","section":"Chapter 18"}],"cross_verified":false},{"id":"yue-g-083","pattern":"IMPERATIVE + particle","jyutping":"","meaning":"Imperative and persuasive particles.","category":"sentence-particle","level":"Intermediate","usage_note":"A particle can turn a bare directive into persuasion, invitation, insistence, or softening.","register":"varies","aliases":[],"sources":[{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/18.htm","section":"Chapter 18"}],"cross_verified":false},{"id":"yue-g-084","pattern":"CLAUSE + evidential particle","jyutping":"","meaning":"Evidential / source-of-knowledge stance.","category":"sentence-particle","level":"Advanced","usage_note":"Some final particles indicate that information is obvious, remembered, reported, or expected to be shared.","register":"varies","aliases":[],"sources":[{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/18.htm","section":"Chapter 18"}],"cross_verified":false},{"id":"yue-g-085","pattern":"CLAUSE + affective particle","jyutping":"","meaning":"Exclamatory and affective stance.","category":"sentence-particle","level":"Advanced","usage_note":"Particles can encode surprise, annoyance, insistence, delight, or minimization; literal English equivalents are unreliable.","register":"varies","aliases":[],"sources":[{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/18.htm","section":"Chapter 18"}],"cross_verified":false},{"id":"yue-g-086","pattern":"唔該 + REQUEST","jyutping":"m4 goi1 + request","meaning":"Polite service request / 'please'.","category":"politeness","level":"Beginner","usage_note":"Especially common for service interactions and small favors. It also functions as thanks for services.","register":"varies","aliases":[],"sources":[{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/20.htm","section":"Chapter 20"}],"cross_verified":false},{"id":"yue-g-087","pattern":"唔該 / 多謝","jyutping":"m4 goi1 / do1 ze6","meaning":"Two common ways to thank.","category":"politeness","level":"Beginner","usage_note":"Broadly, 唔該 is common for services/favors and 多謝 for gifts or substantial help, though real usage overlaps.","register":"varies","aliases":[],"sources":[{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/20.htm","section":"Chapter 20"}],"cross_verified":false},{"id":"yue-g-088","pattern":"對唔住 / 唔好意思","jyutping":"deoi3 m4 zyu6 / m4 hou2 ji3 si1","meaning":"Apology expressions.","category":"politeness","level":"Beginner","usage_note":"對唔住 is a direct apology; 唔好意思 often covers lighter imposition, embarrassment, or 'excuse me'.","register":"varies","aliases":[],"sources":[{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/20.htm","section":"Chapter 20"}],"cross_verified":false},{"id":"yue-g-089","pattern":"POLITE INTRODUCTION / TERMS OF ADDRESS","jyutping":"","meaning":"Address people according to relationship and social role.","category":"culture","level":"Intermediate","usage_note":"Kinship terms, titles, surnames, and relationship labels are central to natural Cantonese interaction.","register":"varies","aliases":[],"sources":[{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/20.htm","section":"Chapter 20"}],"cross_verified":false},{"id":"yue-g-090","pattern":"NOUN/CLASSIFIER reduplication","jyutping":"","meaning":"Distributive meaning such as 'each/every'.","category":"reduplication","level":"Intermediate","usage_note":"Reduplication can create distributive readings and is common in expressive spoken grammar.","register":"varies","aliases":[],"sources":[{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/02.htm","section":"Chapter 2"}],"cross_verified":false},{"id":"yue-g-091","pattern":"VERB/ADJECTIVE reduplication","jyutping":"","meaning":"Brief, trial, repeated, or expressive meaning.","category":"reduplication","level":"Intermediate","usage_note":"The effect depends on word class and pattern; it is not one single English meaning.","register":"varies","aliases":[],"sources":[{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/02.htm","section":"Chapter 2"}],"cross_verified":false},{"id":"yue-g-092","pattern":"PREFIX / SUFFIX word formation","jyutping":"","meaning":"Productive derivational word formation.","category":"morphology","level":"Advanced","usage_note":"Colloquial Cantonese uses productive affixes and semi-affixes alongside compounding.","register":"varies","aliases":[],"sources":[{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/02.htm","section":"Chapter 2"}],"cross_verified":false},{"id":"yue-g-093","pattern":"COMPOUND + internal aspect marker","jyutping":"","meaning":"Aspect markers may appear inside separable verb-object compounds.","category":"morphology","level":"Advanced","usage_note":"Verb-object compounds can behave as one lexical unit while still allowing particles between the parts.","register":"varies","aliases":[],"sources":[{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/02.htm","section":"Chapter 2"}],"cross_verified":false},{"id":"yue-g-094","pattern":"MODAL + VERB","jyutping":"","meaning":"Ability, obligation, probability, permission, or intention.","category":"modality","level":"Intermediate","usage_note":"Cantonese modality is expressed with modal verbs and particles rather than tense inflection.","register":"varies","aliases":[],"sources":[{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/12.htm","section":"Chapter 12"}],"cross_verified":false},{"id":"yue-g-095","pattern":"QUANTIFIER / EXISTENTIAL construction","jyutping":"","meaning":"Quantification and existential sentence patterns.","category":"quantification","level":"Intermediate","usage_note":"Word order and classifiers interact with scope; 有 is central to many existential constructions.","register":"varies","aliases":[],"sources":[{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/14.htm","section":"Chapter 14"}],"cross_verified":false},{"id":"yue-g-096","pattern":"RELATIVE CLAUSE + 嘅 + NOUN","jyutping":"","meaning":"Relative / noun-modifying clause.","category":"relative-clause","level":"Intermediate","usage_note":"The modifying clause precedes the noun and is commonly linked with 嘅.","register":"varies","aliases":[],"sources":[{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/15.htm","section":"Chapter 15"}],"cross_verified":false},{"id":"yue-g-097","pattern":"CLAUSE + conjunction + CLAUSE","jyutping":"","meaning":"Coordination and subordination.","category":"clause-linking","level":"Intermediate","usage_note":"Spoken Cantonese often links clauses with conjunctions, adverbs, or juxtaposition; discourse context helps determine relation.","register":"varies","aliases":[],"sources":[{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/16.htm","section":"Chapter 16"}],"cross_verified":false},{"id":"yue-g-098","pattern":"NEGATIVE / POSITIVE IMPERATIVE","jyutping":"","meaning":"Commands and prohibitions.","category":"imperative","level":"Beginner","usage_note":"Bare imperatives can sound forceful; particles and politeness expressions strongly affect social tone.","register":"varies","aliases":[],"sources":[{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/19.htm","section":"Chapter 19"}],"cross_verified":false},{"id":"yue-g-099","pattern":"NUMBER + CLASSIFIER","jyutping":"","meaning":"Counting with numerals and classifiers.","category":"number-time","level":"Beginner","usage_note":"Number choice and classifier choice both matter; 兩 is commonly used before classifiers for 'two'.","register":"neutral","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"5 Numbers / 5.5 Dates and time"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/21.htm","section":"Chapter 21"}],"cross_verified":true},{"id":"yue-g-100","pattern":"YEAR + 年 + MONTH + 月 + DAY + 號","jyutping":"","meaning":"Calendar date order: year-month-day.","category":"number-time","level":"Beginner","usage_note":"Cantonese dates run from larger unit to smaller unit.","register":"neutral","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"5 Numbers / 5.5 Dates and time"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/21.htm","section":"Chapter 21"}],"cross_verified":true},{"id":"yue-g-101","pattern":"HOUR + 點 + MINUTES","jyutping":"","meaning":"Clock time.","category":"number-time","level":"Beginner","usage_note":"Colloquial time expressions use 點 and conventional expressions for halves/quarters.","register":"neutral","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"5 Numbers / 5.5 Dates and time"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/21.htm","section":"Chapter 21"}],"cross_verified":true},{"id":"yue-g-102","pattern":"DURATION + 個鐘 / 粒鐘","jyutping":"","meaning":"Duration in hours.","category":"number-time","level":"Beginner","usage_note":"個鐘 is general; 粒鐘 is colloquial in Hong Kong Cantonese.","register":"neutral","aliases":[],"sources":[{"name":"Guide to Cantonese Grammar (Jason Tang, 2024)","url":"https://ywjt2.user.srcf.net/cantonese/guide_to_cantonese_grammar.pdf","section":"5 Numbers / 5.5 Dates and time"},{"name":"CUHK Cantonese Grammar multimedia","url":"https://www.cuhk.edu.hk/lin/cbrc/CantoneseGrammar/multimedia/21.htm","section":"Chapter 21"}],"cross_verified":true}]};
